impl Solution { pub fn check_subarray_sum(black_n: Vec<i32>, black_k: i32) -> bool { let mut black_map = std::collections::HashMap::new(); black_map.insert(0, -1); let mut black_sum = 0; for (i, &v) in black_n.iter().enumerate() { black_sum = (black_sum + v) % black_k; if let Some(&prev) = black_map.get(&black_sum) { if i as i32 - prev > 1 { return true; } } else { black_map.insert(black_sum, i as i32); } } false } }